#include <stdio.h>
#include <stdbool.h>

int main()
{
    int board[4][4] = {0};
    for (int i = 0; i < 4; i++)
        for (int j = 0; j < 4; j++) {
            char c;
            scanf("%c ", &c);
            if (c == 'x') board[i][j] = 1;
            else if (c == 'o') board[i][j] = -3;
            else board[i][j] = 0;
        }
    bool can_win = false;
    for (int i = 0; !can_win && i < 4; i++) {
        for (int j = 0; j < 4; j++) {
            if (board[i][j] >= 0) { /* 'x' or '.' */
                int sum_hor = 0, sum_dia_up = 0, sum_dia_down = 0, sum_ver = 0;
                if (j < 2)
                    sum_hor = board[i][j] + board[i][j+1] + board[i][j+2];
                if (i < 2)
                    sum_ver = board[i][j] + board[i+1][j] + board[i+2][j];
                if (i < 2 && j < 2)
                    sum_dia_up = board[i][j] + board[i+1][j+1] + board[i+2][j+2];
                if (i >= 2 && j < 2)
                    sum_dia_down = board[i][j] + board[i-1][j+1] + board[i-2][j+2];

                if (sum_hor == 2 || sum_dia_up == 2 || sum_dia_down == 2 || sum_ver == 2) {
                    can_win = true;
                    break;
                }
            }
        }
    }
    if (can_win)
        puts("YES");
    else
        puts("NO");
    return 0;
}

