#![allow(unused_imports)]
use std::io::*;
use std::cmp::*;
use std::collections::*;

macro_rules! debug(
    ($($arg:tt)*) => { {
        let r = writeln!(&mut ::std::io::stderr(), $($arg)*);
        r.expect("failed printing to stderr");
    } }
);

struct Scanner {
   buffer : std::collections::VecDeque<String>
}

impl Scanner {

   fn new() -> Scanner {
      Scanner {
         buffer: std::collections::VecDeque::new()
      }
   }

   fn process(&mut self) -> String {
      if self.buffer.len() == 0 {
         let mut input = String::new();
         std::io::stdin().read_line(&mut input).ok();
         for word in input.split_whitespace() {
            self.buffer.push_back(word.to_string())
         }
      }

      self.buffer.pop_front().unwrap()
   }

   #[allow(dead_code)]
   fn next<T : std::str::FromStr >(&mut self) -> T {
      self.process().parse::<T>().ok().unwrap()
   }

   #[allow(dead_code)]
   fn next_char(&mut self) -> char {
      self.process().into_bytes()[0] as char
   }
}

fn count_char(x : char, y : char, z : char, target : char) -> i32 {
   (if x == target {1} else {0})
      + if y == target {1} else {0}
      + if z == target {1} else {0}
}

fn check_board(board: &[[char; 4];4]) -> String {
   // horizontal...
   for i in 0..4 {
      for j in 1..3 {
         let x_count = count_char(board[i][j], board[i][j+1], board[i][j-1], 'x');
         let e_count = count_char(board[i][j], board[i][j+1], board[i][j-1], '.');

         if x_count == 3 || (x_count == 2 && e_count == 1) {
            return "YES".to_string();
         }
      }
   }

   // vertical...
   for j in 0..4 {
      for i in 1..3 {
         let x_count = count_char(board[i][j], board[i+1][j], board[i-1][j], 'x');
         let e_count = count_char(board[i][j], board[i+1][j], board[i-1][j], '.');

         if x_count == 3 || (x_count == 2 && e_count == 1) {
            return "YES".to_string();
         }
      }
   }

   // left-diagonal...
   for j in 0..2 {
      for i in 0..2 {
         let x_count = count_char(board[i][j], board[i+1][j+1], board[i+2][j+2], 'x');
         let e_count = count_char(board[i][j], board[i+1][j+1], board[i+2][j+2], '.');

         if x_count == 3 || (x_count == 2 && e_count == 1) {
            return "YES".to_string();
         }
      }
   }

   // right-diagonal..
   for j in 0..2 {
      for i in 2..4 {
         let x_count = count_char(board[i][j], board[i-1][j+1], board[i-2][j+2], 'x');
         let e_count = count_char(board[i][j], board[i-1][j+1], board[i-2][j+2], '.');

         if x_count == 3 || (x_count == 2 && e_count == 1) {
            return "YES".to_string();
         }
      }
   }

   return "NO".to_string();
}

fn main() {
   let mut sin = Scanner::new();

   let mut board = [['.';4];4];

   for i in 0..4 {
      let line = sin.next::<String>().into_bytes();
      for j in 0..4 {
         board[i][j] = line[j] as char;
      }
   }

   println!("{}", check_board(&board));
}
